API_name: nchu_course_teachers_search_by_department
Description:
{
  "description": "從課程資料依系所搜尋中興大學教師。",
  "required_parameters": [
    {
      "name": "department",
      "type": "STRING",
      "description": "系所名稱（支援部分比對）"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "最多回傳幾筆結果（預設為 50）",
      "default": 50
    }
  ]
}

